    if(ih)svg+='<rect x="'+(cx-1)+'" y="'+(y+2)+'" width="'+(cw+2)+'" height="'+(sh-5)+'" rx="3" fill="#fef3c7" stroke="#f59e0b" stroke-width="1.5"/>';
    svg+='<text x="'+(cx+3)+'" y="'+(y+sh/2+1)+'" fill="'+(ih?'#92400e':'#94a3b8')+'" font-size="'+(ih?13:11)+'" font-weight="'+(ih?'bold':'normal')+'" dominant-baseline="middle">'+lv+'단</text>';
